import { fromOpenAI } from '@instructor-ai/instructor';
import { OpenAI } from 'openai';
import { z } from ‘zod';

const CodeGenerationSchema = z.object({
  language: z.enum(['python', 'javascript', 'typescript']),
  code: z.string().min(1),
  tests: z.array(z.string()),
  dependencies: z.array(z.string()).default([]),
  description: z.string().max(200)
});

type CodeGenerationResponse = z.infer<typeof CodeGenerationSchema>;

const client = fromOpenAI(new OpenAI());

const response = await client.chat.completions.create({
  model: 'gpt-4o',
  messages: [{ role: 'user', content: 'Write TypeScript binary search' }],
  response_model: CodeGenerationSchema
}) as CodeGenerationResponse;

console.log(response.code);

def iterate_refinement(task: str, max_iterations: int = 5):
    feedback = ""
    for i in range(max_iterations):
        response = client.messages.create(
            model="gpt-4o",
            response_model=CodeGenerationResponse,
            messages=[
                {"role": "user", "content": task},
                {"role": "system", "content": f"Previous feedback: {feedback}"}
            ]
        )

        exec_result = execute_sandboxed(response.code, response.tests, response.dependencies)

        if exec_result["passed"]:
            return response

        feedback = f"Tests failed: {exec_result['error']}"

    raise Exception("Max iterations exceeded")

